effect.shader:
vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

void main() {

    float r = 1.;

    vec2 st = acLayerNorm;
    st -= 0.5;
    st *= 2.0;
    st.x *= acLayerSize.x/acLayerSize.y;

    st = st * 10.0 / max(0.0001,zdist+10.0);

    float dist = length(st)/r;
    if( dist > 1. )
        discard;

    float height = sqrt(1.-dist*dist);
    vec3 norm = normalize(vec3(st,height));

    vec3 light = normalize(vec3(lightDir.x,-lightDir.y,lightDepth+zdist));
    //light = (vec4(light,1.)*lightOrient).xyz;
    float lum = dot(norm,light);

    norm = normalize((vec4(norm,1.) * orient).xyz);

    vec2 uv = vec2(
        0.5 + atan(norm.z,norm.x) / 6.2831853072,
        0.5 + asin(norm.y)/3.14159
    );

    uv.x *= repeatx;
    uv.y *= repeaty;

    if( mirror ) {
        uv.x = abs(mod(uv.x,2.0)-1.0);
        uv.y = abs(mod(uv.y,2.0)-1.0);
    } else {
        uv.x = mod(uv.x,1.0);
        uv.y = mod(uv.y,1.0);
    }

    uv.x = 1.0-uv.x;

    float pix = 1.0/min(acLayerSize.x,acLayerSize.y);

    uv -= 0.5;
    uv *= 1.0-(2.0*pix);
    uv += 0.5;

    vec4 texColor = texture2DCv(inputImg.texture,l2s(uv));
    if( enableLight ) {
        texColor.rgb *= lum*lightIntensity*lightColor.rgb;
    }
    gl_FragColor = texColor;
}
